var input = inputs.Length > 0 && inputs[0] != null ? inputs[0]! :
    new PixelBuffer(context.TileSize, context.TileSize);

var count = Math.Max(2, GetInt(parameters, "count", 4));
var layout = GetChoice(parameters, "layout", "horizontal");
var gridCols = Math.Max(1, GetInt(parameters, "gridColumns", 4));
var intensity = GetFloat(parameters, "variationIntensity", 0.3f);
var seed = GetInt(parameters, "seed", context.Seed);
var showBorder = GetBool(parameters, "showBorder", false);

var tileW = input.Width;
var tileH = input.Height;

int outW, outH;
int cols, rows;

switch (layout)
{
    case "vertical":
        cols = 1;
        rows = count;
        outW = tileW;
        outH = tileH * count;
        break;
    case "grid":
        cols = Math.Min(count, gridCols);
        rows = (count + cols - 1) / cols;
        outW = tileW * cols;
        outH = tileH * rows;
        break;
    default: // horizontal
        cols = count;
        rows = 1;
        outW = tileW * count;
        outH = tileH;
        break;
}

var output = new PixelBuffer(outW, outH);

output.ParallelForEachPixel((x, y) =>
{
    // Determine which tile cell we're in
    var cellX = x / tileW;
    var cellY = y / tileH;
    var index = cellY * cols + cellX;

    if (index >= count)
    {
        output.SetPixel(x, y, 0, 0, 0, 1);
        return;
    }

    // Calculate position within the tile
    var tx = x % tileW;
    var ty = y % tileH;

    // Check border
    if (showBorder && (tx == 0 || ty == 0 || tx == tileW - 1 || ty == tileH - 1))
    {
        output.SetPixel(x, y, 1, 1, 1, 1);
        return;
    }

    // Sample from input
    var (r, g, b, a) = input.GetPixel(tx, ty);

    // Apply per-tile variation based on index
    if (intensity > 0.001f && index > 0)
    {
        var tileSeed = seed + index * 137;
        var nx = HashToUnit(tx * 7 + tileSeed, ty * 13 + tileSeed * 3, 111);
        var ny = HashToUnit(tx * 11 + tileSeed * 5, ty * 7 + tileSeed, 222);
        var nz = HashToUnit(tx * 3 + tileSeed * 7, ty * 11 + tileSeed * 11, 333);

        var shift = intensity * 0.15f;
        r = Math.Clamp(r + (nx - 0.5f) * shift, 0f, 1f);
        g = Math.Clamp(g + (ny - 0.5f) * shift, 0f, 1f);
        b = Math.Clamp(b + (nz - 0.5f) * shift, 0f, 1f);
    }

    output.SetPixel(x, y, r, g, b, a);
});

return output;
